<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Falling Sand Sandbox</title>
    <style>
        :root {
            --bg-color: #121212;
            --panel-color: #1e1e1e;
            --text-color: #e0e0e0;
            --accent-color: #bb86fc;
        }

        body {
            margin: 0;
            padding: 0;
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            overflow: hidden;
        }

        #container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 20px;
            padding: 25px;
            background-color: var(--panel-color);
            border-radius: 16px;
            box-shadow: 0 15px 35px rgba(0,0,0,0.7);
        }

        canvas {
            background-color: #000;
            border: 2px solid #333;
            border-radius: 8px;
            image-rendering: pixelated;
            cursor: crosshair;
            width: 500px;
            height: 500px;
        }

        .controls {
            display: flex;
            flex-wrap: wrap;
            justify-content: center;
            gap: 12px;
            max-width: 520px;
        }

        button {
            padding: 10px 18px;
            border: none;
            border-radius: 6px;
            background-color: #333;
            color: white;
            cursor: pointer;
            font-weight: 6    t;
            text-transform: uppercase;
            letter-spacing: 1px;
            transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
            box-shadow: 0 3px 6px rgba(0,0,0,0.3);
        }

        button:hover {
            background-color: #444;
            transform: translateY(-2px);
        }

        button:active {
            transform: translateY(0);
        }

        button.active {
            background-color: var(--accent-color);
            color: #000;
            box-shadow: 0 0 15px rgba(187, 134, 252, 0.4);
        }

        #clear {
            background-color: #cf6679;
            color: #000;
        }

        #clear:hover {
            background-color: #ff758c;
        }

        .mat-sand { border-bottom: 4px solid #d2b48c; }
        .mat-water { border-bottom: 4px solid #3498db; }
        .mat-wall { border-bottom: 4px solid #7f8c8d; }
        .mat-acid { border-bottom: 4px solid #2ecc71; }
        .mat-empty { border-bottom: 4px solid #333; }

    </style>
</head>
<body>

<div id="container">
    <canvas id="sand" width="100" height="100"></canvas>

    <div class="controls">
        <button id="mat-sand" class="mat-sand active">Sand</button>
        <button id="mat-water" class="mat-water">Water</button>
        <button id="mat-acid" class="mat-acid">Acid</button>
        <button id="mat-wall" class="mat-wall">Wall</button>
        <button id="mat-empty" class="mat-empty">Eraser</button>
        <div style="width: 100%; height: 0;"></div>
        <button id="clear">Clear All</button>
    </div>
</div>

<script>
    const canvas = document.getElementById('sand');
    const ctx = canvas.getContext('2d', { alpha: false });
    const width = 100;
    const height = 100;

    let grid = new Array(width * height).fill('empty');
    let currentMaterial = 'sand';

    const colors = {
        empty: '#1a1a1a',
        sand: '#d2b48c',
        water: '#3498db',
        wall: '#7f8c8d',
        acid: '#2ecc71'
    };

    window    window.sim = {
        w: width,
        h: height,
        get: (x, y) => {
            if (x < 0 || x >= width || y < 0 || y >= height) return 'wall';
            return grid[y * width + x];
        },
        set: (x, y, material) => {
            if (x >= 0 && x < width && y >= 0 && y < height) {
                grid[y * width + x] = material;
            }
        },
        clear: () => { grid.fill('empty'); },
        tick: (n) => {
            for (let i = 0; i < n; i++) updateSimulation();
        }
    };

    function updateSimulation() {
        // Bottom-up, Right-to-left to prevent double-processing in one tick.
        for (let y = height - 1; y >= 0; y--) {
            for (let x = width - 1; x >= 0; x--) {
                const idx = y * width + x;
                const material = grid[idx];

                if (material === 'wall' || material === 'empty') continue;

                // Acid Dissolve Logic
                if (material === 'acid') {
                    const neighbors = [[0, 1], [0, -1], [1, 0], [-1, 0]];
                    for (let i = 0; i < neighbors.length; i++) {
                        const nx = x + neighbors[i][0];
                        const ny = y + neighbors[i][1];
                        if (nx >= 0 && nx < width && ny >= 0 && ny < height) {
                            const nIdx = ny * width + nx;
                            const neighborMat = grid[nIdx];
                            if (neighborMat === 'sand' || neighborMat === 'wall') {
                                grid[idx] = 'empty';
                                grid[nIdx] = 'empty';
                                break; 
                            }
                        }
                    }
                }

                // Re-check if cell was emptied by acid reaction
                if (grid[idx] === 'empty') continue;

                const currentMat = grid[idx];
                if (currentMat === 'sand') {
                    if (canMoveTo(x, y + 1)) moveParticle(x, y, x, y + 1);
                    else if (canMoveTo(x - 1, y + 1)) moveParticle(x, y, x - 1, y + 1);
                    else if (canMoveTo(x + 1, y + 1)) moveParticle(x, y, x + 1, y + 1);
                } else if (currentMat === 'water' || currentMat === 'acid') {
                    if (canMoveTo(x, y + 1)) moveParticle(x, y, x, y + 1);
                    else if (canMoveTo(x - 1, y + 1)) moveParticle(x, y, x - 1, y + 1);
                    else if (canMoveTo(x + 1, y + 1)) moveParticle(x, y, x + 1, y + 1);
                    else if (canMoveTo(x - 1, y)) moveParticle(x, y, x - 1, y);
                    else if (canMoveTo(x + 1, y)) moveParticle(x, y, x + 1, y);
                }
            }
        }
    }

    function canMoveTo(x, y) {
        if (x < 0 || x >= width || y < 0 || y >= height) return false;
        const target = grid[y * width + x];
        return target === 'empty' || target === 'water' || target === 'acid';
    }

    function moveParticle(x1, y1, x2, y2) {
        const idx1 = y1 * width + x1;
        const idx2 = y2 * width + x2;
        const sourceMat = grid[idx1];
        const targetMat = grid[idx2];
        grid[idx1] = targetMat;
        grid[idx2] = sourceMat;
    }

    function render() {
        const imgData = ctx.createImageData(width, height);
        for (let i = 0; i < grid.length; i++) {
            const colorStr = colors[grid[i]];
            const r = parseInt(colorStr.slice(1, 3), 16);
            const g = parseInt(colorStr.slice(3, 5), 16);
            const b = parseInt(colorStr.slice(5, 7), 16);
            const p = i * 4;
            imgData.data[p] = r;
            imgData.data[p+1] = g;
            imgData.data[p+2] = b;
            imgData.data[p+3] = 255;
        }
        ctx.putImageData(imgData, 0, 0);
    }

    let isDrawing = false;
    function paint(e) {
        const rect = canvas.getBoundingClientRect();
        const x = Math.floor((e.clientX - rect.left) * (width / rect.width));
        const y = Math.floor((e.clientY - rect.top) * (height / rect.height));
        for(let dy = -1; dy <= 1; dy++) {
            for(let dx = -1; dx <= 1; dx++) {
                window.sim.set(x + dx, y + dy, currentMaterial);
            }
        }
    }

    canvas.addEventListener('mousedown', (e) => { isDrawing = true; paint(e); });
    window.addEventListener('mouseup', () => { isDrawing = false; });
    canvas.addEventListener('mousemove', (e) => { if (isDrawing) paint(e); });

    const buttons = document.querySelectorAll('.controls button:not(#clear)');
    buttons.forEach(btn => {
        btn.addEventListener('click', () => {
            buttons.forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            currentMaterial = btn.id.replace('mat-', '');
        });
    });

    document.getElementById('clear').addEventListener('click', () => window.sim.clear());

    function loop() {
        window.sim.tick(1);
        render();
        requestAnimationFrame(loop);
    }

    requestAnimationFrame(loop);
</script>
</body>
</html>
